sql:
SELECT gene_name 
FROM genes 
WHERE hgnc_id = (SELECT hgnc_id FROM gene_versions WHERE version_number = (SELECT MAX(version_number) FROM gene_versions));

SELECT g.gene_name, p.protein_name
FROM genes g
INNER JOIN proteins p ON g.uniprot_id = p.uniprot_id;

SELECT hgnc_id, gene_name 
FROM genes
WHERE LENGTH(gene_name) = (
  SELECT MAX(LENGTH(gene_name)) 
  FROM genes
);

SELECT gf.function_description
FROM gene_functions AS gf
INNER JOIN access_logs AS al ON gf.hgnc_id = al.hgnc_id;

SELECT DISTINCT user_id
FROM access_logs
WHERE access_date >= '2023-05-01' AND access_type = 'view';

SELECT AVG(molecular_weight) 
FROM proteins 
WHERE sequence LIKE '%sequence%';

SELECT molecular_weight
FROM proteins
WHERE protein_name = 'Beta-1,3-N-acetylglucosaminyltransferase 7';

SELECT uniprot_id, protein_name
FROM proteins
WHERE uniprot_id = 'B7ZKY3';

